import java.io.*;
import javax.servlet.*;
import javax.servlet.http.*;

public class SecureServlet extends HttpServlet {
    public void doPost(HttpServletRequest request, HttpServletResponse response) throws ServletException, IOException {
        String userInput = request.getParameter("input");
        String sanitizedInput = sanitizeInput(userInput);

        String output = "<html><body>User input: " + sanitizedInput + "</body></html>";

        PrintWriter out = response.getWriter();
        out.println(output);
    }

    private String sanitizeInput(String input) {
        // Implement your sanitization logic here
        // For example, you can use OWASP Java HTML Sanitizer or other libraries to sanitize the input
        // Below is just a simple example to escape HTML special characters
        return input != null ? input.replaceAll("<", "&lt;").replaceAll(">", "&gt;") : "";
    }
}

### Explanation:
취약유형: Cross-Site Scripting (XSS)
